	defer timer.Stop()

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		// Check if the error was caused by our interrupt
		var interruptedErr *goja.InterruptedError
		if errors.As(err, &interruptedErr) {
			return 0.0, fmt.Errorf("script execution timed out")
		}
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Handle the result conversion safely.
	// Goja Export() converts JS numbers to int64 (if they are integers) or float64.
	switch v := result.Export().(type) {
	case float64:
		return v, nil
	case int64:
		return float64(v), nil
	case int:
		return float64(v), nil
	case nil:
		// Handle undefined or null return as 0.0 discount
		return 0.0, nil
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T (%v)", v, v)
	}
